SELECT id, 5, 'Procedimento', E'**Fase 1 — Ingestão e Organização (Dia 1)**\n1. Transferir arquivos para estrutura de pastas padronizada: RAW/CAM_A, RAW/CAM_B, RAW/DRONE, AUDIO, REFERENCIAS, EXPORTS\n2. Confirmar integridade dos arquivos (checksum MD5)\n3. Backup imediato na nuvem (Google Drive Shared Drive)\n4. Criar projeto no software de edição e sincronizar áudio com vídeo\n\n**Fase 2 — Montagem Offline (Dias 2–4)**\n1. Assistir todo material e marcar takes favoritos\n2. Montar primeiro rascunho seguindo roteiro/storyboard\n3. Revisão interna (Líder AV + Diretor Criativo) em reunião de 45 min\n4. Incorporar feedback e fechar corte para aprovação do cliente\n\n**Fase 3 — Aprovação do Cliente (Dias 5–6)**\n1. Exportar link privado (Vimeo/Frame.io) com prazo de feedback de 48h\n2. Incorporar feedback via Atendimento (máx. 2 rodadas)\n3. Emitir aditivo se alterações excederem escopo contratual\n\n**Fase 4 — Color Grading (Dias 7–8)**\n1. Balancear exposição e balanço de branco\n2. Aplicar look criativo alinhado ao briefing\n3. Garantir consistência entre câmeras e cenas\n4. Revisar em monitor calibrado (Rec.709)\n\n**Fase 5 — Mix de Áudio (Dias 8–9)**\n1. Limpar ruídos de fundo (iZotope RX)\n2. Normalizar loudness: -14 LUFS para web, -23 LUFS para broadcast\n3. Mixar versão com e sem narração quando aplicável\n\n**Fase 6 — Exports Finais (Dia 10)**\n1. Renderizar master ProRes 4444 para arquivo\n2. Exportar: H.264 1080p, 4K, 9:16 vertical, 1:1 feed\n3. Nomear: [CLIENTE]_[EMPREEND]_[TIPO]_[RES]_v[N]_[DATA].mp4\n4. Upload para pasta de entrega + enviar link ao Atendimento', 'step', 4
FROM knowledge_sops WHERE slug = 'tbo-av-009-pos-producao-edicao-color-finalizacao'
UNION ALL
