-- ============================================================
-- SOP 3: Precificação de Projetos por BU
-- ============================================================
INSERT INTO knowledge_sops (title, slug, bu, category, status, priority, tags, content, created_by, version, last_reviewed_at)
VALUES (
  'Precificação de Projetos por BU: Método e Composição de Preço',
  'tbo-com-009-precificacao-projetos-por-bu',
  'comercial',
  'processo',
  'published',
  'critical',
  ARRAY['precificação', 'proposta', 'preço', 'margem', 'custo', 'comercial', 'BU'],
  E'## Precificação de Projetos por BU: Método e Composição de Preço\n\n### Objetivo\nEstabelecer o método padrão da TBO para precificar projetos em cada BU, garantindo margem de contribuição adequada, cobertura de custos diretos e indiretos, e competitividade de mercado. Eliminar precificações por "feeling" e criar consistência comercial.\n\n### Escopo\nAplica-se a todos os projetos de todas as BUs. Executado pelo Diretor Comercial (Ruy) com suporte do Financeiro e dos líderes de BU. Toda proposta comercial acima de R$5.000 deve passar por esse processo antes do envio ao cliente.\n\n### RACI\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|-----------|-------------|-----------|------------|-----------|\n| Levantamento de horas/custos | Líder de BU | Dir. Comercial | Time da BU | — |\n| Composição do preço | Dir. Comercial | Founder | CFO/Financeiro | — |\n| Validação de margem | Financeiro | Founder | Dir. Comercial | — |\n| Aprovação final para envio | Founder | — | Dir. Comercial | Atendimento |\n| Desconto acima de 10% | Founder | — | Dir. Comercial | Financeiro |\n\n### Pré-requisitos\n- Briefing validado com escopo claro e definido\n- Lista de entregas (deliverables) acordada com Atendimento\n- Tabela de custos operacionais da BU atualizada (salários, softwares, infraestrutura)\n- Tabela de preços de referência da TBO (atualizada trimestralmente)\n- Histórico de projetos similares para benchmark interno\n\n### Procedimento\n\n#### Etapa 1 — Levantamento de Custos Diretos\n\n**1.1. Estimar horas por função**\nPara cada entrega do projeto, o Líder de BU estima:\n- Horas de execução (por função: Sênior, Pleno, Júnior, Estagiário)\n- Horas de gestão (Líder de BU: geralmente 15-20% do total de horas de execução)\n- Horas de QA/revisão (10% do total de horas)\n\n**1.2. Calcular custo de horas**\nUsar custo-hora interno por função:\n- Founder/Diretoria: R$X/h (definido internamente)\n- Líder/Sênior: R$X/h\n- Pleno: R$X/h\n- Júnior: R$X/h\n- Estagiário: R$X/h\n*(Valores confidenciais — consultar tabela interna no TBO OS → Financeiro → Tabela de Custos)*\n\n**1.3. Adicionar custos variáveis**\n- Softwares específicos (licenças por projeto)\n- Terceiros e freelancers estimados\n- Deslocamentos, impressões, produção física\n- Farm de render (D3D) ou equipamentos especiais (AV)\n\n#### Etapa 2 — Composição do Preço de Venda\n\n**Fórmula base TBO:**\n```\nPreço de Venda = (Custo Direto × Markup BU) + Overhead + Margem de Lucro\n```\n\n**Markup por BU (referência — ajustar conforme mercado):**\n- Digital 3D: 2.5–3.5x custo direto\n- Branding: 3.0–4.0x custo direto\n- Marketing: 2.5–3.5x custo direto\n- Audiovisual: 3.0–4.5x custo direto\n- Gamificação: 3.5–5.0x custo direto\n\n**Overhead (rateio de custos fixos):**\n- Aplicar 25-35% sobre o custo direto como contribuição aos custos fixos da TBO\n\n**Margem de lucro líquida esperada:**\n- Projetos pequenos (<R$10k): mín. 25%\n- Projetos médios (R$10k–50k): mín. 30%\n- Projetos grandes (>R$50k): mín. 35%\n\n#### Etapa 3 — Validação de Margem\n1. Financeiro revisa a composição no simulador de margem (TBO OS → Financeiro)\n2. Valida que:\n   - Margem bruta ≥ 60% do preço de venda\n   - Margem líquida ≥ patamar definido por tamanho\n   - Custo de freelancers ≤ 30% do custo direto total\n3. Sinaliza aprovação ou solicita ajuste ao Dir. Comercial\n\n#### Etapa 4 — Estratégia de Precificação\n\n**Ancoragem:** Apresentar sempre 3 opções (Básico, Recomendado, Premium)\n- Básico: escopo mínimo, menor prazo, sem extras\n- Recomendado: escopo completo, prazo padrão TBO (principal oferta)\n- Premium: escopo expandido, prazo premium, serviços adicionais\n\n**Posicionamento:** A TBO não compete por preço. Se o cliente questionar preço, reforçar:\n- Qualidade cinematográfica / fotorrealismo de alto nível\n- Prazo confiável (SLA documentado)\n- Equipe especializada (não freelancer avulso)\n- Suporte pós-entrega\n\n**Desconto máximo sem aprovação do Founder:** 10%\n**Desconto acima de 10%:** requer aprovação do Founder + justificativa registrada no CRM\n\n#### Etapa 5 — Formalização na Proposta\n1. Inserir preços na proposta comercial seguindo template padrão (SOP tbo-com-002)\n2. Descrever escopo de forma clara: o que está incluído e o que NÃO está incluído\n3. Especificar:\n   - Número de rodadas de revisão incluídas\n   - Prazo de entrega (em dias úteis)\n   - Condições de pagamento (adiantamento, parcelas, saldo)\n   - Validade da proposta (15 dias corridos)\n4. Registrar proposta no CRM (TBO OS → Comercial → Pipeline)\n\n### Checklist de Validação\n- [ ] Horas estimadas por função revisadas pelo Líder de BU\n- [ ] Custos variáveis (freelancers, softwares, produção) incluídos\n- [ ] Markup dentro do range definido para a BU\n- [ ] Overhead aplicado (25-35%)\n- [ ] Margem líquida validada pelo Financeiro\n- [ ] 3 opções de escopo preparadas (Básico, Recomendado, Premium)\n- [ ] Escopo descrito com clareza (incluídos E não incluídos)\n- [ ] Rodadas de revisão especificadas\n- [ ] Proposta registrada no CRM antes do envio\n\n### Ferramentas e Recursos\n- **Simulador de margem**: TBO OS → Financeiro → Simulador de Proposta\n- **Tabela de custos internos**: TBO OS → Financeiro → Tabela de Custos (restrita: founder + diretoria)\n- **Histórico de projetos**: TBO OS → Relatórios → Lucratividade por Projeto\n- **Template de proposta**: SOP tbo-com-002\n- **Pipeline CRM**: TBO OS → Comercial\n\n### SLAs e Métricas\n| Métrica | Meta |\n|---------|------|\n| Tempo de precificação (briefing → proposta) | ≤ 3 dias úteis |\n| Margem bruta média da TBO | ≥ 65% |\n| Margem líquida média | ≥ 30% |\n| Taxa de conversão proposta → contrato | ≥ 35% |\n| Propostas dentro do escopo original | ≥ 80% (sem aditivos por sub-precificação) |\n| Desconto médio concedido | ≤ 7% |\n\n### Troubleshooting\n\n**Líder de BU subestima horas (sub-precificação recorrente)**\n→ Cruzar com histórico de projetos similares no TBO OS. Adicionar buffer de 20% em projetos com escopo incerto. Revisar estimativas com o time antes de fechar.\n\n**Cliente resiste ao preço e exige desconto além do autorizado**\n→ Acionar o Founder para decisão estratégica. Avaliar: estratégico para portfólio? Longo prazo? Caso contrário, manter preço ou declinar com elegância.\n\n**Concorrente apresentou preço 40% menor**\n→ Não entrar em leilão de preço. Reforçar diferenciação de qualidade. Documentar no CRM para análise de posicionamento.\n\n**Projeto com escopo vago — difícil precificar**\n→ Solicitar briefing mais detalhado antes de precificar. Alternativa: proposta por hora (time & material) com estimativa de range.\n\n### Template Anexo — Simulador de Precificação\n\n```markdown\n# Simulador de Precificação — [CLIENTE] / [PROJETO]\nData: _______ | BU: _______ | Responsável: _______\n\n## Custo Direto\n| Função | Horas | Custo/h | Subtotal |\n|--------|-------|---------|----------|\n| Líder/Sênior | ___ | R$___ | R$___ |\n| Pleno | ___ | R$___ | R$___ |\n| Júnior | ___ | R$___ | R$___ |\n| Freelancer | ___ | R$___ | R$___ |\n| **Subtotal Horas** | | | **R$___** |\n\n## Custos Variáveis\n| Item | Valor |\n|------|-------|\n| Softwares/licenças | R$___ |\n| Produção/impressão | R$___ |\n| Farm de render | R$___ |\n| Outros | R$___ |\n| **Subtotal Variáveis** | **R$___** |\n\n## Composição do Preço\n| Item | Valor |\n|------|-------|\n| Custo Direto Total | R$___ |\n| Overhead (___%) | R$___ |\n| **Custo Total** | **R$___** |\n| Markup aplicado (___x) | — |\n| **Preço de Venda** | **R$___** |\n| Margem Bruta | ___% |\n| Margem Líquida (estimada) | ___% |\n\n## Validação\n- Aprovado pelo Financeiro: Sim / Não — Data: _______\n- Aprovado pelo Founder (se desconto >10%): Sim / N/A\n```',
  '00000000-0000-0000-0000-000000000000',
  1,
  NOW()
);

